import {
  Component,
  DestroyRef,
  inject,
  Injectable,
  OnInit,
  signal,
  ViewChild,
} from '@angular/core';
import { InsEditor } from '../../../../app/editor/components/editor/editor.component';
import { FormControl, ReactiveFormsModule } from '@angular/forms';
import {
  provideInsEditor,
  provideInsEditorCollaboration,
  provideInsEditorCollaborationUser,
} from '../../../../app/editor/providers';
import { InsDropdown, InsTextfield } from '@liuk123/insui';
import { INS_ATTACH_FILES_LOADER } from '../../../../app/editor/common/files-loader';
import { fromEvent, map, Observable, of, switchMap } from 'rxjs';
import { InsEditorAttachedFile } from '../../../../app/editor/common/attached';

@Injectable({ providedIn: 'root' })
export class HttpMockUploader {
  public save(_base64: string): Observable<string> {
    return of(
      // mock
      'https://private-user-images.githubusercontent.com/20438370/398424241-231fe6f0-6c0a-481f-8856-f5da3a10f06b.mp4?jwt=eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9..8idoj74wxtWsQgdhSL09qvWp62Mv7Mzkl3uuiDYUyD4',
    );
  }
}

@Component({
  selector: 'app-tiptap',
  imports: [InsEditor, ReactiveFormsModule, InsTextfield, InsDropdown],
  templateUrl: './tiptap.html',
  styleUrl: './tiptap.less',
  providers: [
    provideInsEditor({
      placeholder: { placeholder: '请输入' },
      heading: { levels: [1, 2, 3, 4, 5, 6] },
      link: { autolink: true, openOnClick: false, linkOnPaste: true },
      collaboration: true,
      collaborationCaret: true,
    }),
    provideInsEditorCollaboration({
      url: 'ws://localhost:1234',
      documentName: 'demo-room',
      field: 'content',
    }),
    provideInsEditorCollaborationUser({
      name: 'Demo User',
      color: '#5B8FF9',
    }),
    {
      provide: INS_ATTACH_FILES_LOADER,
      deps: [HttpMockUploader],
      useFactory:
        (uploader: HttpMockUploader) =>
        ([file]: File[]): Observable<Array<InsEditorAttachedFile>> => {
          if (!file) {
            return of([]);
          }
          const fileReader = new FileReader();
          fileReader.readAsDataURL(file);

          return fromEvent<any>(fileReader, 'load').pipe(
            switchMap(() => uploader.save(String(fileReader.result))),
            map((src) => [
              {
                // Do not return base64 instead of link to binary
                // because it's bad idea for your performance

                src,
                name: file.name,
                attrs: { type: file.type },
              },
            ]),
          );
        },
    },
  ],
})
export class Tiptap implements OnInit {
  @ViewChild(InsEditor)
  private readonly wysiwyg?: InsEditor;


  protected control = new FormControl('');

  ngOnInit(): void {
    // this.control.valueChanges
    //   .pipe(takeUntilDestroyed(this.destroy$))
    //   .subscribe(() => {
    //     const hasSlash = !!this.wysiwyg?.selectionState.before.startsWith('/')
    //     console.log('hasSlash',hasSlash)
    //     this.open.set(!!this.wysiwyg?.isLinkSelected?false: hasSlash)
    // })
  }
  onFileAttached(files: InsEditorAttachedFile[]) {
    console.log('files', files);
    files.forEach((file) => this.wysiwyg?.editor?.setFileBlock(file));
  }
  getJson() {
    console.log('json', this.wysiwyg?.editor?.json);
  }
  setValue() {
    this.wysiwyg?.editor?.setJsonValue({
      type: 'doc',
      content: [
        {
          type: 'image',
          attrs: {
            src: 'data:image/png;base64,',
            name: null,
            align: null,
            caption: '123',
            showPreview: true,
            previewWidth: 284,
          },
        },
        {
          type: 'paragraph',
          attrs: {
            textAlign: null,
          },
        },
      ],
    });
  }
  async exportDocx(){
    let blob = await this.wysiwyg?.editor?.exportDocx()
    if(!blob){ return }
    const url = window.URL.createObjectURL(blob)
    const anchor = document.createElement('a')
    anchor.href = url
    anchor.download = 'demo.docx'
    anchor.click()
    anchor.remove()
    window.URL.revokeObjectURL(url)

  }
}
